   248→export default function Home() {
   249→  const [projects, setProjects] = useState<Project[]>([]);
   250→  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
   251→  const [showNameModal, setShowNameModal] = useState(false);
   252→  const [showAuthModal, setShowAuthModal] = useState(false);
   253→  const [pendingIdea, setPendingIdea] = useState<string | null>(null);
   254→  const [isCreatingProject, setIsCreatingProject] = useState(false); // Track if we're in project creation flow
   255→  const { showToast } = useToast();
   256→  const { isAuthenticated, isLoading } = useAuth();
   257→
   258→  useEffect(() => {
   259→    const loadedProjects = loadState<Project[]>(STORAGE_KEYS.PROJECTS, []);
   260→    setProjects(loadedProjects);
   261→  }, []);
   262→
   263→  useEffect(() => {
   264→    saveState(STORAGE_KEYS.PROJECTS, projects);
   265→  }, [projects]);
   266→
   267→  const createProject = (name: string, idea: string) => {
   268→    const newProject: Project = {
   269→      id: crypto.randomUUID(),
   270→      name: name,
   271→      createdAt: new Date().toISOString(),
   272→      lastModified: new Date().toISOString(),
   273→      progress: 0,
   274→      currentStep: 0,
   275→      status: 'draft',
   276→      data: {
   277→        intake: {} as any,
   278→        brief: {} as any,
   279→        market: {} as any,
   280→        strategy: {} as any,
   281→        specifications: {} as any,
   282→        features: [],
   283→        steps: [
   284→          { id: 0, title: 'Brain Dump', description: 'Idéation', status: StepStatus.IN_PROGRESS },
   285→          { id: 1, title: 'Cadrage BMAD', description: 'Validation', status: StepStatus.LOCKED },
   286→          { id: 2, title: 'Features', description: 'Roadmap', status: StepStatus.LOCKED },
   287→          { id: 3, title: 'Architecture', description: 'Tech', status: StepStatus.LOCKED },
   288→          { id: 4, title: 'Design & Livrable', description: 'Export', status: StepStatus.LOCKED },
   289→        ],
   290→        brainDump: {
   291→            rawText: idea,
   292→            selectedSource: 'raw',
   293→            history: { suggestions: [], ideas: [] }
   294→        }
   295→      }
   296→    };
   297→    setProjects([...projects, newProject]);
   298→    setCurrentProjectId(newProject.id);
   299→    setShowNameModal(false);
   300→    setPendingIdea(null);
   301→    setIsCreatingProject(false);
   302→    showToast('success', 'Projet créé !');
   303→  };
   304→
   305→  const handleInstantCreate = (idea: string) => {
   306→    if (!idea || !idea.trim()) {
   307→      showToast('error', 'Veuillez décrire votre idée avant de démarrer');
   308→      return;
   309→    }
   310→
   311→    setPendingIdea(idea);
   312→    setIsCreatingProject(true);
   313→
   314→    // Check if user is authenticated
   315→    if (!isAuthenticated) {
   316→      setShowAuthModal(true);
   317→    } else {
   318→      setShowNameModal(true);
   319→    }
   320→  };
   321→
   322→  const handleAuthSuccess = () => {
   323→    setShowAuthModal(false);
   324→
   325→    // Only open name modal if we're in project creation flow
   326→    if (isCreatingProject && pendingIdea) {
   327→      setShowNameModal(true);
   328→    } else {
   329→      // Just simple login, show success message
   330→      showToast('success', 'Connexion réussie !');
   331→    }
   332→  };
   333→
   334→  const handleLoginClick = () => {
   335→    // Simple login from header, not creating a project
   336→    setIsCreatingProject(false);
   337→    setPendingIdea(null);
   338→    setShowAuthModal(true);
   339→  };
   340→
   341→  const handleCloseAuth = () => {
   342→    setShowAuthModal(false);
   343→    if (!isCreatingProject) {
   344→      // If not creating project, clear pending idea
   345→      setPendingIdea(null);
   346→    }
   347→  };
   348→
   349→  const handleCloseNameModal = () => {
   350→    setShowNameModal(false);
   351→    setPendingIdea(null);
   352→    setIsCreatingProject(false);
   353→  };
   354→
   355→  const handleUpdateProject = (updatedProject: Project) => {
   356→    setProjects(prev => prev.map(p => p.id === updatedProject.id ? updatedProject : p));
   357→  };
   358→
   359→  const handleStepChange = (stepId: number) => {
   360→    const current = projects.find(p => p.id === currentProjectId);
   361→    if (current) {
   362→        handleUpdateProject({ ...current, currentStep: stepId });
   363→    }
   364→  };
   365→
   366→  const currentProject = projects.find(p => p.id === currentProjectId);
   367→
   368→  const handleSaveBrainDump = useCallback((bd: any) => {
   369→    setProjects(prev => prev.map(p =>
   370→      p.id === currentProjectId
   371→        ? {...p, data: {...p.data, brainDump: bd}}
   372→        : p
   373→    ));
   374→  }, [currentProjectId]);
   375→
   376→  if (!currentProject) {
   377→    return (
   378→      <div className="min-h-screen bg-black text-white font-sans selection:bg-white/20">
   379→        <Header onLoginClick={handleLoginClick} />
   380→        <CockpitState onInstantCreate={handleInstantCreate} />
   381→
   382→        <LoginRegisterModal
   383→          isOpen={showAuthModal}
   384→          onClose={handleCloseAuth}
   385→          onSuccess={handleAuthSuccess}
   386→        />
   387→
   388→        {showNameModal && (
   389→            <NameProjectModal
   390→                isOpen={showNameModal}
   391→                onClose={handleCloseNameModal}
   392→                onSubmit={(name) => {
   393→                  if (pendingIdea && name.trim()) {
   394→                    createProject(name, pendingIdea);
   395→                  } else {
   396→                    showToast('error', 'Nom du projet requis');
   397→                  }
   398→                }}
   399→            />
   400→        )}
   401→      </div>
   402→    );
   403→  }
   404→
   405→  const activeStep = currentProject.currentStep;
   406→
   407→  const renderContent = () => {
   408→    switch (activeStep) {
   409→        case 0: return <BrainDump project={currentProject} onComplete={(ext, text) => {
   410→            const nextStep = 1;
   411→            const updatedSteps = currentProject.data.steps.map(s => s.id === nextStep ? { ...s, status: StepStatus.IN_PROGRESS } : s.id === 0 ? { ...s, status: StepStatus.COMPLETE } : s);
   412→            handleUpdateProject({
   413→                ...currentProject,
   414→                currentStep: nextStep,
   415→                data: { ...currentProject.data, steps: updatedSteps }
   416→            });
   417→        }} onSaveDraft={handleSaveBrainDump} />;
   418→        
   419→        case 1: return <BrainstormingWizard initialData={currentProject.data.brainDump} onComplete={(res) => {
   420→             const nextStep = 2;
   421→             const updatedSteps = currentProject.data.steps.map(s => s.id === nextStep ? { ...s, status: StepStatus.IN_PROGRESS } : s.id === 1 ? { ...s, status: StepStatus.COMPLETE } : s);
   422→             handleUpdateProject({ ...currentProject, currentStep: nextStep, data: { ...currentProject.data, steps: updatedSteps, intake: res.intake } });
   423→        }} />;
   424→        
   425→        case 2: return <FeaturesManager project={currentProject} onUpdateFeatures={(feats) => handleUpdateProject({...currentProject, data: {...currentProject.data, features: feats}})} onNext={() => {
   426→            const nextStep = 3;
   427→            const updatedSteps = currentProject.data.steps.map(s => s.id === nextStep ? { ...s, status: StepStatus.IN_PROGRESS } : s.id === 2 ? { ...s, status: StepStatus.COMPLETE } : s);
   428→            handleUpdateProject({ ...currentProject, currentStep: nextStep, data: { ...currentProject.data, steps: updatedSteps }});
   429→        }} />;
   430→        
   431→        case 3: return <TechArchitecture project={currentProject} onUpdate={(arch) => handleUpdateProject({...currentProject, data: {...currentProject.data, architecture: arch}})} onGenerate={() => {}} isGenerating={false} />;
   432→        
   433→        case 4: return <PackagePreview project={currentProject} artifacts={{}} />;
   434→        
   435→        default: return <div className="p-10 text-center text-gray-500">Étape en construction</div>;
   436→    }
   437→  };
   438→
   439→  return (
   440→    <div className="flex h-screen bg-[#070707] text-[#F2F2F2] overflow-hidden font-sans">
   441→        <Sidebar 
   442→            currentStep={activeStep} 
   443→            steps={currentProject.data.steps} 
   444→            project={currentProject}
   445→            onNavigate={handleStepChange}
   446→            onDashboard={() => setCurrentProjectId(null)}
   447→            onRename={(newName) => handleUpdateProject({...currentProject, name: newName})}
   448→        />
   449→        <main className="flex-1 overflow-y-auto relative">
   450→            {renderContent()}
   451→        </main>
   452→    </div>
   453→  );
   454→}
