     4→const ANTHROPIC_API_URL = 'https://api.anthropic.com/v1/messages';
     5→const ANTHROPIC_VERSION = '2023-06-01';
     6→const DEFAULT_MODEL = 'claude-3-5-sonnet-20241022';
     7→const DEFAULT_MAX_TOKENS = 4096;
     8→const DEFAULT_TEMPERATURE = 0.7;
     9→
    10→// Types
    11→interface AnthropicRequestBody {
    12→  model?: string;
    13→  max_tokens?: number;
    14→  temperature?: number;
    15→  system?: string;
    16→  messages: Array<{
    17→    role: 'user' | 'assistant';
    18→    content: string | Array<{ type: string; text?: string; [key: string]: any }>;
    19→  }>;
    20→}
    21→
    22→// Error handling
    23→class APIError extends Error {
    24→  constructor(
    25→    message: string,
    26→    public status: number,
    27→    public code: string
    28→  ) {
    29→    super(message);
    30→    this.name = 'APIError';
    31→  }
    32→}
    33→
    34→export async function POST(req: NextRequest) {
    35→  try {
    36→    // Validate API Key
    37→    const apiKey = process.env.ANTHROPIC_API_KEY;
    38→    if (!apiKey) {
    39→      console.error('[API] Missing ANTHROPIC_API_KEY in environment');
    40→      return NextResponse.json(
    41→        { error: 'Configuration error: Missing API key' },
    42→        { status: 500 }
    43→      );
    44→    }
    45→
    46→    // Parse request body
    47→    let body: AnthropicRequestBody;
    48→    try {
    49→      body = await req.json();
    50→    } catch (parseError) {
    51→      return NextResponse.json(
    52→        { error: 'Invalid JSON in request body' },
    53→        { status: 400 }
    54→      );
    55→    }
    56→
    57→    // Validate required fields
    58→    if (!body.messages || !Array.isArray(body.messages) || body.messages.length === 0) {
    59→      return NextResponse.json(
    60→        { error: 'Missing or invalid "messages" field' },
    61→        { status: 400 }
    62→      );
    63→    }
    64→
    65→    // Build Anthropic request payload
    66→    const anthropicPayload = {
    67→      model: body.model || DEFAULT_MODEL,
    68→      max_tokens: body.max_tokens || DEFAULT_MAX_TOKENS,
    69→      temperature: body.temperature ?? DEFAULT_TEMPERATURE,
    70→      ...(body.system && { system: body.system }),
    71→      messages: body.messages,
    72→    };
    73→
    74→    // Call Anthropic API
    75→    const anthropicResponse = await fetch(ANTHROPIC_API_URL, {
    76→      method: 'POST',
    77→      headers: {
    78→        'Content-Type': 'application/json',
    79→        'x-api-key': apiKey,
    80→        'anthropic-version': ANTHROPIC_VERSION,
    81→      },
    82→      body: JSON.stringify(anthropicPayload),
    83→    });
    84→
    85→    // Handle Anthropic API errors
    86→    if (!anthropicResponse.ok) {
    87→      const errorData = await anthropicResponse.json().catch(() => ({}));
    88→      
    89→      console.error('[API] Anthropic API error:', {
    90→        status: anthropicResponse.status,
    91→        statusText: anthropicResponse.statusText,
    92→        error: errorData,
    93→      });
    94→
    95→      // Map Anthropic errors to client-friendly messages
    96→      let errorMessage = 'AI service error';
    97→      let errorCode = 'ANTHROPIC_ERROR';
    98→
    99→      switch (anthropicResponse.status) {
   100→        case 400:
   101→          errorMessage = 'Invalid request format';
   102→          errorCode = 'INVALID_REQUEST';
   103→          break;
   104→        case 401:
   105→          errorMessage = 'Authentication failed';
   106→          errorCode = 'AUTH_ERROR';
   107→          break;
   108→        case 429:
   109→          errorMessage = 'Rate limit exceeded. Please try again later.';
   110→          errorCode = 'RATE_LIMIT';
   111→          break;
   112→        case 500:
   113→        case 503:
   114→          errorMessage = 'AI service temporarily unavailable';
   115→          errorCode = 'SERVICE_UNAVAILABLE';
   116→          break;
   117→      }
   118→
   119→      return NextResponse.json(
   120→        { 
   121→          error: errorMessage,
   122→          code: errorCode,
   123→          status: anthropicResponse.status,
   124→        },
   125→        { status: anthropicResponse.status }
   126→      );
   127→    }
   128→
   129→    // Return successful response
   130→    const data = await anthropicResponse.json();
   131→    return NextResponse.json(data, { status: 200 });
   132→
   133→  } catch (error: any) {
   134→    console.error('[API] Unexpected error:', error);
   135→    
   136→    return NextResponse.json(
   137→      { 
   138→        error: 'Internal server error',
   139→        code: 'INTERNAL_ERROR',
   140→      },
   141→      { status: 500 }
   142→    );
   143→  }
   144→}
   145→
   146→// Health check endpoint
   147→export async function GET() {
   148→  const hasKey = !!process.env.ANTHROPIC_API_KEY;
   149→  
   150→  return NextResponse.json({
   151→    status: 'ok',
   152→    service: 'anthropic-proxy',
   153→    configured: hasKey,
   154→    model: DEFAULT_MODEL,
   155→    max_tokens: DEFAULT_MAX_TOKENS,
   156→  });
   157→}
