     7→// --- TYPES & ERREURS ---
     8→
     9→export class AIError extends Error {
    10→  code: string;
    11→  originalError?: any;
    12→  isRetryable: boolean;
    13→  status?: number;
    14→
    15→  constructor(message: string, code: string, isRetryable = false, originalError?: any, status?: number) {
    16→    super(message);
    17→    this.name = 'AIError';
    18→    this.code = code;
    19→    this.isRetryable = isRetryable;
    20→    this.originalError = originalError;
    21→    this.status = status;
    22→  }
    23→}
    24→
    25→// --- API CONFIGURATION ---
    26→
    27→const API_ENDPOINT = '/api/anthropic';
    28→const DEFAULT_MODEL = 'claude-3-5-sonnet-20241022';
    29→const DEFAULT_MAX_TOKENS = 4096;
    30→
    31→// --- CORE: ROBUST EXECUTION WITH EXPONENTIAL BACKOFF ---
    32→
    33→const executeWithRetry = async <T>(
    34→  operation: () => Promise<T>,
    35→  retries = 3,
    36→  baseDelay = 1000,
    37→  signal?: AbortSignal
    38→): Promise<T> => {
    39→
    40→  let attempt = 0;
    41→
    42→  while (attempt <= retries) {
    43→    if (signal?.aborted) throw new AIError("Opération Annulée.", "ABORTED");
    44→
    45→    try {
    46→      return await operation();
    47→    } catch (error: any) {
    48→      const status = error.status || (error.response ? error.response.status : null);
    49→      const msg = (error.message || '').toLowerCase();
    50→
    51→      // ERREURS FATALES (400, 401, Invalid Key)
    52→      if (status === 400 || status === 401 || msg.includes('key') || msg.includes('invalid_argument') || msg.includes('authentication')) {
    53→        console.error("[AI] Fatal Error (Auth/Request):", error);
    54→        throw new AIError(
    55→          "Clé API Expirée Ou Requête Invalide.",
    56→          "FATAL_AUTH_ERROR",
    57→          false,
    58→          error,
    59→          status
    60→        );
    61→      }
    62→
    63→      // ERREURS TEMPORAIRES (503, 429, Overloaded)
    64→      const isOverloaded = status === 503 || msg.includes('overloaded') || msg.includes('unavailable');
    65→      const isRateLimit = status === 429 || msg.includes('rate_limit') || msg.includes('resource exhausted');
    66→
    67→      if (isOverloaded || isRateLimit) {
    68→        attempt++;
    69→        if (attempt > retries) {
    70→          throw new AIError("Service IA Saturé. Réessayez Plus Tard.", "SERVICE_OVERLOADED", true, error, status);
    71→        }
    72→
    73→        // Exponential Backoff: 1s, 2s, 4s...
    74→        const delay = Math.min(10000, baseDelay * Math.pow(2, attempt)) + Math.random() * 500;
    75→        console.warn(`[AI] Surcharge (${status}). Tentative ${attempt}/${retries} dans ${Math.round(delay)}ms...`);
    76→        await new Promise(resolve => setTimeout(resolve, delay));
    77→        continue;
    78→      }
    79→
    80→      throw new AIError("Erreur Générique IA.", "UNKNOWN_ERROR", false, error);
    81→    }
    82→  }
    83→  throw new Error("Unreachable Code");
    84→};
    85→
    86→// --- PARSING ROBUSTE ---
    87→
    88→const safeJsonParse = <T>(text: string | undefined, fallback: T): T => {
    89→  if (!text) return fallback;
    90→  try {
    91→    let cleanText = text.replace(/```json\n?|```/g, '').trim();
    92→    try {
    93→      return JSON.parse(cleanText);
    94→    } catch (directError) {
    95→      const objectMatch = cleanText.match(/\{[\s\S]*\}/);
    96→      const arrayMatch = cleanText.match(/\[[\s\S]*\]/);
    97→
    98→      let bestMatch = '';
    99→      if (cleanText.trim().startsWith('[') && arrayMatch) bestMatch = arrayMatch[0];
   100→      else if (objectMatch) bestMatch = objectMatch[0];
   101→      else if (arrayMatch) bestMatch = arrayMatch[0];
   102→
   103→      if (bestMatch) return JSON.parse(bestMatch);
   104→      throw new Error("Structure JSON Introuvable");
   105→    }
   106→  } catch (e) {
   107→    console.warn("JSON Parse Failed:", e);
   108→    return fallback;
   109→  }
   110→};
