   118→): Promise<string> => {
   119→  const response = await fetch(API_ENDPOINT, {
   120→    method: 'POST',
   121→    headers: {
   122→      'Content-Type': 'application/json',
   123→    },
   124→    body: JSON.stringify({
   125→      model,
   126→      max_tokens: DEFAULT_MAX_TOKENS,
   127→      messages: [
   128→        {
   129→          role: 'user',
