   202→export const generateDivergentIdeas = async (baseText: string, level: CreativityLevel, avoidTitles: string[] = [], language: 'fr' | 'en' = 'fr'): Promise<IdeaCard[]> => {
   203→    let prompt = buildCreativePrompt(level, baseText, avoidTitles);
   204→
   205→    // RETRY LOOP FOR QUANTITY GUARANTEE
   206→    let attempts = 0;
   207→    const maxAttempts = 3;
   208→    let finalCards: IdeaCard[] = [];
   209→
   210→    while (attempts < maxAttempts) {
   211→      try {
   212→        const responseText = await executeWithRetry<string>(() => callClaude(prompt, 'claude-3-5-sonnet-20241022'), 3, 1000);
   213→
   214→        let rawCards = safeJsonParse(responseText, [] as any[]);
   215→
   216→        // Map raw response to IdeaCard strict structure
   217→        let mappedCards = rawCards.map((c: any) => ({
   218→            id: crypto.randomUUID(),
   219→            title: c.title || "Idée Sans Titre",
   220→            description: c.description || c.proposal || "Description Manquante",
   221→            proposal: c.description || c.proposal || "Description Manquante",
   222→            tag: c.tag || "Product",
   223→            method: c.method || "Creative Engine",
   224→            rationale: c.rationale || "Généré par IA",
   225→            intensity: c.intensity || level,
   226→            confidence: c.confidence || "medium",
   227→            category: c.category || "Product",
   228→            framework: "creative_engine",
   229→            priority: "p2"
   230→        })) as IdeaCard[];
   231→
   232→        // Accumulate ideas if prompt loop
   233→        finalCards = [...finalCards, ...mappedCards];
   234→
   235→        // Dedup by title
   236→        finalCards = finalCards.filter((v,i,a)=>a.findIndex(t=>(t.title === v.title))===i);
   237→
   238→        if (finalCards.length >= MIN_IDEAS_PER_MODE) {
   239→          break; // Success
   240→        } else {
   241→          console.warn(`[AI] Generated only ${finalCards.length} ideas. Retrying...`);
   242→          prompt += "\n\nATTENTION: Tu n'as pas généré assez d'idées. Génère-en 5 NOUVELLES différentes maintenant.";
   243→          attempts++;
   244→        }
   245→      } catch (error) {
   246→        console.error(`[AI] Generation attempt ${attempts} failed:`, error);
   247→        attempts++;
   248→        if (attempts >= maxAttempts) throw error;
   249→      }
   250→    }
   251→
   252→    // FALLBACK IF STILL MISSING
   253→    if (finalCards.length < MIN_IDEAS_PER_MODE) {
   254→      console.warn(`[AI] Filling with fallback ideas. Found ${finalCards.length}, need ${MIN_IDEAS_PER_MODE}.`);
   255→      const fallbackCards = getFallbackIdeas(level, MIN_IDEAS_PER_MODE - finalCards.length);
   256→      finalCards = [...finalCards, ...fallbackCards];
   257→    }
   258→
   259→    return finalCards.slice(0, Math.max(MIN_IDEAS_PER_MODE, finalCards.length));
   260→};
