     7→// --- TYPES & ERREURS ---
     8→
     9→export class AIError extends Error {
    10→  code: string;
    11→  originalError?: any;
    12→  isRetryable: boolean;
    13→  status?: number;
    14→
    15→  constructor(message: string, code: string, isRetryable = false, originalError?: any, status?: number) {
    16→    super(message);
    17→    this.name = 'AIError';
    18→    this.code = code;
    19→    this.isRetryable = isRetryable;
    20→    this.originalError = originalError;
    21→    this.status = status;
    22→  }
    23→}
    24→
    25→// --- API CONFIGURATION ---
    26→
    27→const API_ENDPOINT = '/api/openai';
    28→const DEFAULT_MODEL = 'gpt-4o';
    29→const DEFAULT_MAX_TOKENS = 4096;
    30→
    31→// --- CORE: ROBUST EXECUTION WITH EXPONENTIAL BACKOFF ---
    32→
    33→const executeWithRetry = async <T>(
    34→  operation: () => Promise<T>,
    35→  retries = 3,
    36→  baseDelay = 1000,
    37→  signal?: AbortSignal
    38→): Promise<T> => {
    39→
    40→  let attempt = 0;
    41→
    42→  while (attempt < retries) {
    43→    if (signal?.aborted) throw new AIError('Opération annulée', 'ABORTED', false);
    44→
    45→    try {
    46→      return await operation();
    47→    } catch (error: any) {
    48→      attempt++;
    49→      const msg = error.message?.toLowerCase() || '';
    50→      const status = error.status || error.response?.status;
    51→
    52→      if (status === 400 || status === 401 || msg.includes('key') || msg.includes('invalid_argument') || msg.includes('authentication')) {
    53→        console.error("[AI] Fatal Error (Auth/Request):", error);
    54→        throw new AIError(
    55→          "Clé API Expirée Ou Requête Invalide.",
    56→          "FATAL_AUTH_ERROR",
    57→          false,
    58→          error,
    59→          status
    60→        );
    61→      }
    62→
    63→      if (attempt >= retries) {
    64→        console.error("[AI] Max Retries Reached:", error);
    65→        throw new AIError(
    66→          "Service IA Indisponible. Veuillez Réessayer Plus Tard.",
    67→          "MAX_RETRIES_EXCEEDED",
    68→          false,
    69→          error,
    70→          status
    71→        );
    72→      }
    73→
    74→      const delay = Math.min(baseDelay * Math.pow(2, attempt), 8000);
    75→      console.warn(`[AI] Retry ${attempt}/${retries} in ${delay}ms...`);
    76→      await new Promise(resolve => setTimeout(resolve, delay));
    77→    }
    78→  }
    79→
    80→  throw new AIError("Échec inattendu", "UNKNOWN_ERROR", false);
    81→};
    82→
    83→// --- HELPERS ---
    84→
    85→const safeJsonParse = <T>(text: string, fallback: T): T => {
    86→  const cleaned = text.replace(/^```json\s*/, '').replace(/\s*```$/, '').trim();
    87→  try {
    88→    return JSON.parse(cleaned);
    89→  } catch (e) {
    90→    console.warn("JSON Parse Failed:", e);
    91→    return fallback;
    92→  }
    93→};
    94→
    95→// --- HELPER: CALL NEXT.JS API ROUTE ---
    96→
    97→const callOpenAI = async (
    98→  userPrompt: string,
    99→  model: string = DEFAULT_MODEL,
   100→  signal?: AbortSignal
   101→): Promise<string> => {
   102→  const response = await fetch(API_ENDPOINT, {
   103→    method: 'POST',
   104→    headers: {
   105→      'Content-Type': 'application/json',
   106→    },
   107→    body: JSON.stringify({
   108→      model,
   109→      max_tokens: DEFAULT_MAX_TOKENS,
   110→      messages: [
   111→        {
   112→          role: 'user',
   113→          content: userPrompt
   114→        }
   115→      ]
   116→    }),
   117→    signal,
   118→  });
   119→
   120→  if (!response.ok) {
   121→    const errorData = await response.json().catch(() => ({}));
   122→    const error: any = new Error(errorData.error || 'API request failed');
   123→    error.status = response.status;
   124→    error.response = { status: response.status };
   125→    throw error;
   126→  }
   127→
   128→  const data = await response.json();
   129→  const content = data.choices?.[0]?.message?.content;
   130→  if (content) {
   131→    return content;
   132→  }
   133→  throw new Error('No content in response');
   134→};
