    19→export function ToastProvider({ children }: { children?: ReactNode }) {
    20→  const [toasts, setToasts] = useState<Toast[]>([]);
    21→
    22→  const showToast = useCallback((type: ToastType, message: string) => {
    23→    const id = Math.random().toString(36).substr(2, 9);
    24→    setToasts(prev => [...prev, { id, type, message }]);
    25→    
    26→    setTimeout(() => {
    27→      setToasts(prev => prev.filter(t => t.id !== id));
    28→    }, 5000);
    29→  }, []);
    30→
    31→  const removeToast = (id: string) => {
    32→    setToasts(prev => prev.filter(t => t.id !== id));
    33→  };
    34→
    35→  return (
    36→    <ToastContext.Provider value={{ showToast }}>
    37→      {children}
    38→      
    39→      <div className="fixed bottom-4 right-4 z-[100] space-y-2 pointer-events-none">
    40→        {toasts.map(toast => (
    41→          <div
    42→            key={toast.id}
    43→            className="flex items-start gap-3 px-4 py-3 rounded-xl shadow-2xl border border-border bg-card pointer-events-auto animate-in slide-in-from-right duration-300 max-w-sm ring-1 ring-inset ring-white/5"
    44→          >
    45→            {toast.type === 'success' && <CheckCircle className="w-5 h-5 text-accent mt-0.5" />}
    46→            {toast.type === 'error' && <AlertCircle className="w-5 h-5 text-accent mt-0.5" />}
    47→            {toast.type === 'info' && <Info className="w-5 h-5 text-muted-foreground mt-0.5" />}
    48→            
    49→            <p className="text-sm font-medium flex-1 text-foreground">
    50→              {toast.message}
    51→            </p>
    52→            
    53→            <button
    54→              onClick={() => removeToast(toast.id)}
    55→              className="text-muted-foreground hover:text-foreground transition-colors"
    56→            >
    57→              <X className="w-4 h-4" />
    58→            </button>
    59→          </div>
    60→        ))}
    61→      </div>
    62→    </ToastContext.Provider>
    63→  );
    64→}
