    23→      if (SpeechRecognition) {
    24→        setIsSupported(true);
    25→        const recognition = new SpeechRecognition();
    26→        recognition.continuous = false;
    27→        recognition.interimResults = false;
    28→        recognition.lang = 'fr-FR';
    29→        recognitionRef.current = recognition;
    30→      }
    31→    }
    32→  }, []);
    33→
    34→  const startListening = (onResult: (text: string) => void) => {
    35→    if (recognitionRef.current) {
    36→      setIsListening(true);
    37→      recognitionRef.current.onresult = (event: any) => {
    38→        const transcript = event.results[0][0].transcript;
